<script setup lang="ts">
const SIM_OPTIONS:any={archetype:['saas','marketplace','consumer','services','fintech','legaltech','healthtech','infrastructure','media','other'],stage:['idea','prototype','pre_revenue','early_revenue','growth','mature'],team_size:['solo','2_5','6_20','21_plus'],ai_spend:['under_250','250_1000','1000_5000','5000_plus'],objectives:['ship_faster','reduce_cost','grow_revenue','improve_quality','reduce_risk','automate_operations','expand_distribution','strengthen_security'],capabilities:['identity','billing','analytics','design_system','legal_ops','customer_support','growth','data_pipeline','ai_routing','security','deployment','research'],tools:['openai','anthropic','google_ai','local_models','vercel','supabase','github','figma','stripe','other'],constraints:['privacy_first','regulated','low_budget','small_team','high_availability','data_residency','no_vendor_lockin']}
const count=ref(3),result=ref<any>(null),loading=ref(false),error=ref('')
const base=()=>({archetype:'saas',stage:'early_revenue',team_size:'2_5',ai_spend:'250_1000',objectives:['ship_faster','reduce_cost'],capabilities:['identity','billing','analytics'],tools:['openai','vercel','github'],constraints:['small_team','privacy_first']})
const ventures=ref<any[]>([base(),{...base(),archetype:'marketplace',capabilities:['identity','billing','customer_support'],tools:['anthropic','vercel','github']},{...base(),archetype:'legaltech',capabilities:['identity','legal_ops','research'],tools:['google_ai','supabase','github']}])
watch(count,n=>{const size=Math.min(25,Math.max(1,Number(n)||1));count.value=size;while(ventures.value.length<size)ventures.value.push(base());ventures.value=ventures.value.slice(0,size)})
const toggle=(row:any,key:string,value:string)=>{const set=new Set(row[key]);set.has(value)?set.delete(value):set.add(value);row[key]=[...set]}
async function simulate(){loading.value=true;error.value='';try{result.value=await $fetch('/api/public/portfolio-simulation',{method:'POST',body:{ventures:ventures.value}})}catch(e:any){error.value=e?.data?.message||e?.message}finally{loading.value=false}}
const pretty=(v:string)=>v.replaceAll('_',' ')
const scrollVenture=(i:number)=>globalThis.document?.getElementById(`v${i}`)?.scrollIntoView({behavior:'smooth',block:'nearest'})
</script>
<template><section id="portfolio-preview" class="safe-sim"><header class="sim-heading"><div><span>PRIVATE, PRE-SIGNUP PORTFOLIO LAB</span><h2>See the system between your companies.<br><em>Without naming a single one.</em></h2></div><p>Use categories only—no company names, URLs, repositories, code, customers, prompts, datasets, or secrets. Madeus returns a directional map and stores nothing.</p></header><div class="privacy-contract"><b>Zero-knowledge intake boundary</b><span>✓ bounded categories only</span><span>✓ stateless response</span><span>✓ no account required</span><span>✓ no sensitive free text</span></div><div class="sim-workspace"><aside><label>Ventures in your portfolio <strong>{{count}}</strong><input v-model.number="count" type="range" min="1" max="25"></label><p>“Five startups” is a founder example, not a product limit. Preview 1–25 here; the authenticated twin has no conceptual portfolio limit.</p><nav><button v-for="(_,i) in ventures" :key="i" type="button" :class="{active:$route.hash===`#v${i}`}" @click="scrollVenture(Number(i))">V{{String(Number(i)+1).padStart(2,'0')}}</button></nav><button class="run" :disabled="loading" @click="simulate">{{loading?'Simulating portfolio…':'Generate private simulation'}} <span>→</span></button></aside><div class="venture-list"><article v-for="(v,i) in ventures" :id="`v${i}`" :key="i"><header><b>Venture {{String(Number(i)+1).padStart(2,'0')}}</b><small>Anonymous categorical profile</small></header><div class="selects"><label>Archetype<select v-model="v.archetype"><option v-for="x in SIM_OPTIONS.archetype" :key="x" :value="x">{{pretty(x)}}</option></select></label><label>Stage<select v-model="v.stage"><option v-for="x in SIM_OPTIONS.stage" :key="x" :value="x">{{pretty(x)}}</option></select></label><label>Team<select v-model="v.team_size"><option v-for="x in SIM_OPTIONS.team_size" :key="x" :value="x">{{pretty(x)}}</option></select></label><label>Monthly AI spend<select v-model="v.ai_spend"><option v-for="x in SIM_OPTIONS.ai_spend" :key="x" :value="x">{{pretty(x)}}</option></select></label></div><div v-for="key in ['objectives','capabilities','tools','constraints']" :key="key" class="chip-row"><span>{{key}}</span><button v-for="x in SIM_OPTIONS[key as keyof typeof SIM_OPTIONS]" :key="x" type="button" :class="{on:v[key].includes(x)}" @click="toggle(v,key,x)">{{pretty(x)}}</button></div></article></div></div><p v-if="error" class="sim-error">{{error}}</p><section v-if="result" class="sim-result"><header><div><span>DIRECTIONAL PORTFOLIO GRAPH</span><h3>{{result.portfolio_size}} anonymous ventures · {{result.hidden_dependencies.length}} shared dependencies</h3></div><strong>{{new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',maximumFractionDigits:0}).format(result.estimated_monthly_savings)}}<small>estimated monthly savings</small></strong></header><div class="result-grid"><article><span>Duplicate work</span><ul><li v-for="x in result.duplicate_patterns" :key="x.pattern"><b>{{x.label}}</b><small>{{x.ventures}} ventures</small></li></ul></article><article><span>Hidden dependencies</span><ul><li v-for="x in result.hidden_dependencies" :key="x.capability"><b>{{pretty(x.capability)}}</b><small>{{x.ventures.join(' · ')}}</small></li></ul></article><article><span>IP exposure</span><div class="risk" :class="result.ip_exposure.level">{{result.ip_exposure.level}}</div><p>{{result.ip_exposure.recommendation}}</p></article></div><div class="actions"><article v-for="(a,i) in result.coordinated_actions" :key="a.title"><span>0{{Number(i)+1}}</span><div><b>{{a.title}}</b><p>{{a.why}}</p><small>{{a.impact}} · {{a.confidence}}% confidence</small></div></article></div><footer><b>Privacy receipt</b> No input stored · no identity requested · bounded categories only · illustrative until authenticated twin verification</footer></section></section></template>
<style scoped>
