play:flex;flex-wrap:wrap;gap:5px;margin-top:9px}.chip-row>span{width:90px;padding-top:6px;color:#647068;font:7px JetBrains Mono,monospace;text-transform:uppercase}.chip-row button{border-radius:999px;padding:6px 8px}.chip-row button.on{border-color:#4d9d70;background:#173324;color:#91dbaf}.sim-result{margin-top:18px;border:1px solid #304439;background:#0b110e}.sim-result>header{display:flex;justify-content:space-between;padding:23px;border-bottom:1px solid #293930}.sim-result h3{margin:6px 0 0;font-size:18px}.sim-result>header strong{font-size:26px;text-align:right}.sim-result>header small{display:block;font-size:7px;color:#718078}.result-grid{display:grid;grid-template-columns:1fr 1fr .8fr}.result-grid article{padding:20px;border-right:1px solid #293930}.result-grid ul{list-style:none;margin:13px 0 0;padding:0}.result-grid li{display:flex;justify-content:space-between;padding:9px 0;border-top:1px solid #202d26;font-size:10px}.risk{display:inline-block;margin:18px 0 8px;padding:6px 9px;border-radius:99px;background:#513a1a;color:#ffc567;font-size:9px;text-transform:uppercase}.risk.contained{background:#163925;color:#76d59d}.result-grid p{font-size:9px;color:#87948d;line-height:1.6}.actions{display:grid;grid-template-columns:repeat(3,1fr);border-top:1px solid #293930}.actions article{display:flex;gap:12px;padding:20px;border-right:1px solid #293930}.actions b{font-size:11px}.actions p,.actions small{font-size:8px;color:#7c8a82;line-height:1.5}.sim-result footer{padding:14px 20px;background:#101b15;color:#71847a;font-size:8px}.sim-error{color:#ff9c8d}@media(max-width:800px){.safe-sim{padding:80px 16px}.sim-heading{grid-template-columns:1fr}.sim-workspace{grid-template-columns:1fr}.sim-workspace aside{position:static;border-right:0;border-bottom:1px solid #2a3931}.selects{grid-template-columns:1fr 1fr}.result-grid,.actions{grid-template-columns:1fr}.chip-row>span{width:100%}}
</style>
